#!/usr/bin/env node
// Pulls the latest Microsoft Graph endpoint + sample data from the
// merill/msgraph skill (https://graph.pm) and writes a focused, typed
// data module the generator uses for permission validation and few-shot.
//
// Run locally with `node scripts/sync-msgraph-data.mjs`, or via the
// weekly GitHub Action that commits the regenerated file.
//
// The full api-docs-index is ~6 MB; we deliberately do NOT ship it
// in our client bundle. We extract only:
//   - the deduped set of all permission scopes (~700)
//   - the curated samples (~16, hand-verified intent→query mappings)
// and write them to a small TS module (~30 KB).

import { writeFileSync, mkdirSync } from "node:fs";
import { dirname, resolve } from "node:path";
import { fileURLToPath } from "node:url";

const HERE = dirname(fileURLToPath(import.meta.url));
const OUT_FILE = resolve(HERE, "..", "src", "lib", "generator-graph-data.ts");

const API_DOCS_URL =
  "https://raw.githubusercontent.com/merill/msgraph/main/skills/msgraph/references/api-docs-index.json";
const SAMPLES_URL =
  "https://raw.githubusercontent.com/merill/msgraph/main/skills/msgraph/references/samples-index.json";

async function fetchJson(url) {
  const res = await fetch(url);
  if (!res.ok) {
    throw new Error(`Failed to fetch ${url}: ${res.status} ${res.statusText}`);
  }
  return res.json();
}

function extractScopes(apiDocs) {
  const set = new Set();
  for (const ep of Object.values(apiDocs.endpoints ?? {})) {
    const perms = ep.permissions ?? {};
    for (const list of [
      perms.delegatedWork,
      perms.delegatedPersonal,
      perms.application,
    ]) {
      if (Array.isArray(list)) {
        for (const scope of list) {
          if (typeof scope === "string" && scope.trim()) {
            set.add(scope.trim());
          }
        }
      }
    }
  }
  return Array.from(set).sort();
}

function extractScopeIndex(apiDocs) {
  // Build a reverse index: scope -> list of "METHOD /path" endpoints that
  // require it. Lets a tool answer "what does this scope actually grant?"
  // without us shipping the full 6,368-endpoint map.
  // Capped at 5 sample endpoints per scope to keep payload small.
  const index = {};
  for (const ep of Object.values(apiDocs.endpoints ?? {})) {
    if (!ep.path || !ep.method) continue;
    const perms = ep.permissions ?? {};
    const all = [
      ...(perms.delegatedWork ?? []),
      ...(perms.delegatedPersonal ?? []),
      ...(perms.application ?? []),
    ];
    const key = `${ep.method.toUpperCase()} ${ep.path}`;
    for (const scope of new Set(all)) {
      if (!index[scope]) index[scope] = [];
      if (index[scope].length < 5) index[scope].push(key);
    }
  }
  return index;
}

function extractSamples(samplesIndex) {
  return (samplesIndex.samples ?? []).map((s) => ({
    intent: s.intent ?? "",
    // Multi-step samples use an array; normalize to a newline-joined string
    // so consumers can treat all samples uniformly.
    query: Array.isArray(s.query) ? s.query.join("\n") : (s.query ?? ""),
    product: s.product ?? "general",
  }));
}

function generateModule({ scopes, scopeIndex, samples, generatedAt }) {
  const header = `// Auto-generated by scripts/sync-msgraph-data.mjs from merill/msgraph.
// DO NOT EDIT BY HAND. Run \`node scripts/sync-msgraph-data.mjs\` to refresh.
// Source: https://graph.pm (https://github.com/merill/msgraph)
//
// Generated: ${generatedAt}
// Scopes: ${scopes.length}
// Samples: ${samples.length}

`;
  return (
    header +
    "export const GRAPH_DATA_GENERATED_AT = " +
    JSON.stringify(generatedAt) +
    ";\n\n" +
    "// Every Microsoft Graph permission scope appearing in any endpoint's\n" +
    "// delegatedWork / delegatedPersonal / application permissions list.\n" +
    "export const GRAPH_SCOPES: ReadonlySet<string> = new Set(" +
    JSON.stringify(scopes) +
    ");\n\n" +
    "// Reverse index: scope -> up to 5 example endpoints that require it.\n" +
    "// Used by the lookupGraphPermission tool to give the model concrete\n" +
    "// usage context, not just a binary 'valid/invalid' answer.\n" +
    "export const GRAPH_SCOPE_INDEX: Readonly<Record<string, readonly string[]>> = " +
    JSON.stringify(scopeIndex) +
    ";\n\n" +
    "// Curated, hand-verified intent → API mappings. Used as few-shot context\n" +
    "// for the Script Generator system prompt and exposed via tool use.\n" +
    "export type GraphSample = {\n" +
    "  intent: string;\n" +
    "  query: string;\n" +
    "  product: string;\n" +
    "};\n" +
    "export const GRAPH_SAMPLES: readonly GraphSample[] = " +
    JSON.stringify(samples, null, 2) +
    ";\n"
  );
}

async function main() {
  console.log("Fetching merill/msgraph data...");
  const [apiDocs, samplesIndex] = await Promise.all([
    fetchJson(API_DOCS_URL),
    fetchJson(SAMPLES_URL),
  ]);

  const scopes = extractScopes(apiDocs);
  const scopeIndex = extractScopeIndex(apiDocs);
  const samples = extractSamples(samplesIndex);
  const generatedAt = new Date().toISOString();

  console.log(`Scopes: ${scopes.length}`);
  console.log(`Scope index entries: ${Object.keys(scopeIndex).length}`);
  console.log(`Samples: ${samples.length}`);

  const source = generateModule({ scopes, scopeIndex, samples, generatedAt });

  mkdirSync(dirname(OUT_FILE), { recursive: true });
  writeFileSync(OUT_FILE, source, "utf-8");
  console.log(`Wrote ${OUT_FILE} (${(source.length / 1024).toFixed(1)} KB)`);
}

main().catch((err) => {
  console.error(err);
  process.exit(1);
});
